{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires a multi-stage approach involving geometric modeling, an adaptive search strategy for minimizing cost, and a verification step to ensure the final guess is accurate.",
  "helpers": [
    {
      "label": "geometric_modeler",
      "instructions": "Represent the known polyomino shapes as sets of relative coordinates. Create a function that can generate all possible valid placements of these shapes within the grid boundaries, accounting for potential overlaps or constraints if specified by the problem context."
    },
    {
      "label": "search_strategy_optimizer",
      "instructions": "Develop an adaptive probing algorithm. This algorithm should decide which cells to drill or which aggregate queries to perform next based on the current information. It must prioritize queries that maximize information gain (e.g., reducing the entropy of the possible polyomino placements) while minimizing the cumulative probing cost."
    },
    {
      "label": "probabilistic_inference_engine",
      "instructions": "Implement a mechanism to update the probability distribution of oil-containing cells based on the results of drilling (binary) and noisy aggregate queries (probabilistic). Use Bayesian updating to refine the likelihood of each cell being part of a polyomino."
    },
    {
      "label": "final_guess_validator",
      "instructions": "Given the posterior probabilities of each cell containing oil, determine the optimal set of cells to return as the FINAL_ANSWER. This should involve selecting the most likely configuration of polyominoes that is consistent with the observed data and minimizes the risk of high-cost errors."
    }
  ],
  "synthesis_brief": "The geometric_modeler provides the search space. The search_strategy_optimizer uses the probabilistic_inference_engine to select queries. The inference engine processes query results to update cell probabilities. Finally, the final_guess_validator uses these probabilities to produce the optimal set of oil-containing cells."
}

